// Basic goroutine
go func() {
	process(data)
}()

// Coordinated with WaitGroup
var wg sync.WaitGroup
for i := 0; i < 10; i++ {
	wg.Add(1)
	i := i // Capture variable
	go func() {
		defer wg.Done()
		process(i)
	}()
}
