principles.goodExample:
// Unbuffered channel
ch := make(chan int)

go func() {
	ch <- 42 // Blocks until received
}()

val := <-ch

// Buffered channel
ch2 := make(chan int, 3)
ch2 <- 1 // Doesn't block
ch2 <- 2
ch2 <- 3

// Directional channels
func producer(ch chan<- int) {
	for i := 0; i < 10; i++ {
		ch <- i
	}
	close(ch)
}

func consumer(ch <-chan int) {
	for val := range ch {
		process(val)
	}
}

principles.badExample:
// Not closing channel
func producer(ch chan int) {
	for i := 0; i < 10; i++ {
		ch <- i
	}
	// Forgot close(ch) - consumer's range will block forever
}

// Sending on closed channel
close(ch)
ch <- 42 // panic!

// Bi-directional when should be directional
func producer(ch chan int) { // Should be chan<- int
	ch <- 42
	val := <-ch // Can receive - probably bug
}

principles.goodExample:
// Producer closes after sending
ch := make(chan int)

go func() {
	for i := 0; i < 10; i++ {
		ch <- i
	}
	close(ch) // Signal completion
}()

// Consumer ranges until closed
for val := range ch {
	process(val)
}

// Check if closed
val, ok := <-ch
if !ok {
	fmt.Println("Channel closed")
}

principles.badExample:
// Receiver closing (dangerous)
ch := make(chan int)

go func() {
	for {
		ch <- rand.Int()
	}
}()

for val := range ch {
	if val == 0 {
		close(ch) // Panic if sender still sending!
		break
	}
}

